javascript:(function(){var U="https://script.google.com/macros/s/AKfycbw2ExFJnz3u4T9bM1Yg27HMvkZw77JVh__WoW0UwjOGtzEOdtkHYVZ9GTfw3xHBXUXEQA/exec";var m=window.location.href.match(/\/dp\/([A-Z0-9]{10})/i)||window.location.href.match(/\/gp\/product\/([A-Z0-9]{10})/i)||window.location.href.match(/[?&]asin=([A-Z0-9]{10})/i);if(!m){show("Not an Amazon product page","error");return;}var asin=m[1].toUpperCase();var title=((document.querySelector("#productTitle")||{}).innerText||"").trim();var pw=((document.querySelector(".a-price-whole")||{}).innerText||"0").replace(/[^0-9]/g,"");var pf=((document.querySelector(".a-price-fraction")||{}).innerText||"00").replace(/[^0-9]/g,"");var price=parseFloat(pw+"."+pf);fetch(U,{method:"POST",mode:"no-cors",headers:{"Content-Type":"application/json"},body:JSON.stringify({asin:asin,title:title,price:isNaN(price)?0:price,url:"https://www.amazon.com/dp/"+asin,seller:(function(){var el=document.querySelector("#bylineInfo");if(!el)return"";var a=el.querySelector("a");return a?a.innerText.trim():el.innerText.replace(/^Visit the\s+/i,"").replace(/\s+Store$/i,"").replace(/^Brand:\s*/i,"").trim();})()})}).then(function(){show("Added: "+(title.substring(0,40)||asin),"ok");}).catch(function(e){show("Error: "+e.message,"error");});function show(msg,type){var b=document.getElementById("__ab__");if(b)b.remove();b=document.createElement("div");b.id="__ab__";b.innerText=msg;Object.assign(b.style,{position:"fixed",top:"20px",right:"20px",zIndex:"999999",padding:"14px 20px",borderRadius:"8px",fontSize:"15px",fontWeight:"bold",fontFamily:"sans-serif",color:"#fff",background:type==="error"?"#c0392b":"#27ae60",boxShadow:"0 4px 12px rgba(0,0,0,0.3)",maxWidth:"360px"});document.body.appendChild(b);setTimeout(function(){b.remove();},4000);}})();
